app = Flask(__name__)

@app.route('/', methods=['GET', 'POST'])
def index():
    if request.method == 'POST':
        newspaper = request.form['newspaper']
        summary = get_summary(newspaper)
        return render_template('index.html', summary=summary)
    return render_template('index.html')

def get_summary(newspaper):
    url = 'https://api.example.com/summarize'
    data = {'newspaper': newspaper}
    response = requests.post(url, json=data)
    return response.json()['summary']

if __name__ == '__main__':
    app.run(debug=True)

import requests

def get_newspaper_summary():
    newspaper = input("Enter the name of the newspaper you want to summarize: ")
    url = f"https://api.claude.ai/v1/summarize?newspaper={newspaper}"
    response = requests.get(url)
    if response.status_code == 200:
        summary = response.json()["summary"]
        print(f"Summary of {newspaper}:")
        print(summary)
    else:
        print("Error: Could not fetch the summary.")

def ask_questions():
    summary = input("Enter the summary you want to ask questions about: ")
    question = input("Enter your question: ")
    url = f"https://api.claude.ai/v1/answer?summary={summary}&question={question}"
    response = requests.get(url)
    if response.status_code == 200:
        answer = response.json()["answer"]
        print(f"Answer: {answer}")
    else:
        print("Error: Could not fetch the answer.")

def main():
    get_newspaper_summary()
    ask_questions()

if __name__ == "__main__":
    main()

