import requests

def get_summary():
    user_input = input("Enter the report you would like to summarize: ")
    url = "https://api.claude.ai/v1/summarize"
    payload = {"text": user_input}
    headers = {
        "Content-Type": "application/json",
        "Authorization": "Bearer YOUR_API_KEY_HERE"
    }
    response = requests.post(url, json=payload, headers=headers)
    if response.status_code == 200:
        summary = response.json()["summary"]
        print(f"Summary: {summary}")
        while True:
            user_question = input("Do you have any questions about the summary? (Enter 'q' to exit) ")
            if user_question.lower() == 'q':
                break
            url = "https://api.claude.ai/v1/answer"
            payload = {"question": user_question, "context": summary}
            response = requests.post(url, json=payload, headers=headers)
            if response.status_code == 200:
                answer = response.json()["answer"]
                print(f"Answer: {answer}")
            else:
                print("Error: Could not get answer from API.")
    else:
        print("Error: Could not get summary from API.")

